import Button from "@hi-ui/button"
import { ClearOutlined } from "@hi-ui/icons"
import QueryFilter, {
  FilterFieldProps,
  FilterDrawer,
  SearchInput,
  FilterButton,
  QueryFilterProvider,
} from "@hi-ui/query-filter"

/**
 * @title \u5168\u90E8\u7B5B\u9009
 */
export const AllFilter = () => {
  const [filterFields, setFilterFields] = React.useState<FilterFieldProps[]>([
    {
      field: "store",
      label: "\u95E8\u5E97",
      visible: true,
      component: (
        <Select
          optionWidth={200}
          clearable
          data={[
            {
              id: "wuhan",
              title: "\u6B66\u6C49\u5206\u5E97",
            },
            {
              id: "beijing",
              title: "\u5317\u4EAC\u5206\u5E97",
            },
            {
              id: "shanghai",
              title: "\u4E0A\u6D77\u5206\u5E97",
            },
          ]}
        />
      ),
    },
    {
      field: "category",
      label: "\u5206\u7C7B",
      visible: true,
      component: (
        <CheckSelect
          optionWidth={200}
          clearable
          dataSource={() => {
            return new Promise((resolve) => {
              setTimeout(() => {
                resolve([
                  {
                    id: "phone",
                    title: "\u624B\u673A",
                  },
                  {
                    id: "computer",
                    title: "\u7535\u8111",
                  },
                  {
                    id: "tablet",
                    title: "\u5E73\u677F",
                  },
                ])
              }, 1000)
            })
          }}
        />
      ),
    },
    {
      field: "cascader",
      label: "\u7EA7\u8054\u9009\u62E9",
      visible: false,
      component: (
        <Cascader
          data={[
            {
              id: "1",
              title: "\u4E00\u7EA7",
              children: [
                {
                  id: "1-1",
                  title: "\u4E8C\u7EA7",
                  children: [
                    {
                      id: "1-1-1",
                      title: "\u4E09\u7EA7",
                    },
                  ],
                },
              ],
            },
          ]}
        />
      ),
    },
    {
      field: "date-picker",
      label: "\u65E5\u671F\u9009\u62E9",
      visible: true,
      component: <DatePicker type="daterange" />,
    },
  ])

  const defaultFormData = {
    store: "",
    category: [],
    cascader: [],
    "date-picker": [],
  }

  const [formData, setFormData] = React.useState<Record<string, unknown>>(defaultFormData)

  const handleChange = (formData: Record<string, unknown>, fields: FilterFieldProps[]) => {
    console.log(formData, fields)

    setFormData(formData)
    setFilterFields(fields)
  }

  const [visible, setVisible] = React.useState(false)

  const showedFields = React.useMemo(() => {
    return filterFields.filter((field) => field.visible)
  }, [filterFields])

  // \u5224\u65AD\u662F\u5426\u4E3A\u7A7A\u503C
  const isEmptyValue = React.useCallback((value: any) => {
    return (
      value === undefined ||
      value === "" ||
      value === null ||
      (Array.isArray(value) && value.length === 0)
    )
  }, [])

  const filteredCount = React.useMemo(() => {
    return Object.values(formData).filter((value) => !isEmptyValue(value)).length
  }, [formData, isEmptyValue])

  return (
    <>
      <h1>AllFilter</h1>
      <div className="query-filter-all-filter__wrap">
        <QueryFilterProvider>
          <QueryFilter
            prepend={<SearchInput placeholder="\u59D3\u540D/\u624B\u673A\u53F7" />}
            append={[
              <FilterButton key="all-filter" count={filteredCount} onClick={() => setVisible(true)}>
                \u5168\u90E8\u7B5B\u9009
              </FilterButton>,
              <React.Fragment key="clear-filter">
                {filteredCount > 0 ? (
                  <Button icon={<ClearOutlined />} onClick={() => setFormData(defaultFormData)}>
                    \u6E05\u7A7A
                  </Button>
                ) : null}
              </React.Fragment>,
            ]}
            filterFields={showedFields}
            formData={formData}
            onChange={setFormData}
          />
          <FilterDrawer
            width={360}
            visible={visible}
            title="\u5168\u90E8\u7B5B\u9009"
            formData={formData}
            // \u5728\u62BD\u5C49\u4E2D\u70B9\u51FB\u786E\u5B9A\u540E\u4F1A\u89E6\u53D1 onChange
            onChange={handleChange}
            // \u5728\u62BD\u5C49\u4E2D\u9009\u4E2D\u63A7\u4EF6\u503C\u540E\u4F1A\u89E6\u53D1 onSelect
            onSelect={(val, allVals, filterField) => {
              console.log("onSelect", val, allVals, filterField)
            }}
            filterFields={filterFields}
            onClose={() => {
              setVisible(false)
            }}
            onPinChange={console.log}
            // \u81EA\u5B9A\u4E49\u62BD\u5C49\u4E2D\u7EC4\u4EF6\u7684 props
            customFieldProps={(filterField) => {
              console.log("customFieldProps", filterField)

              if (filterField.field === "cascader") {
                return {
                  overlay: {
                    placement: "bottom-end",
                  },
                }
              }

              if (filterField.field !== "date-picker") {
                return {
                  optionWidth: undefined,
                }
              }
            }}
          />
        </QueryFilterProvider>
      </div>
    </>
  )
}`,title:"\u5168\u90E8\u7B5B\u9009",description:"null",mdxType:"CodeBlock"}),mdx("h2",t({},{id:"props"}),"Props"),mdx("h3",t({},{id:"queryfilter-props"}),"QueryFilter Props"),mdx("table",null,mdx("thead",{parentName:"table"},mdx("tr",{parentName:"thead"},mdx("th",t({parentName:"tr"},{align:null}),"\u53C2\u6570"),mdx("th",t({parentName:"tr"},{align:null}),"\u8BF4\u660E"),mdx("th",t({parentName:"tr"},{align:null}),"\u7C7B\u578B"),mdx("th",t({parentName:"tr"},{align:null}),"\u53EF\u9009\u503C"),mdx("th",t({parentName:"tr"},{align:null}),"\u9ED8\u8BA4\u503C"))),mdx("tbody",{parentName:"table"},mdx("tr",{parentName:"tbody"},mdx("td",t({parentName:"tr"},{align:null}),"onChange"),mdx("td",t({parentName:"tr"},{align:null}),"\u8868\u5355\u6570\u636E\u53D8\u5316\u56DE\u8C03"),mdx("td",t({parentName:"tr"},{align:null}),"((formData: Record<string, unknown",">",") => void)"),mdx("td",t({parentName:"tr"},{align:null}),"-"),mdx("td",t({parentName:"tr"},{align:null}),"-")),mdx("tr",{parentName:"tbody"},mdx("td",t({parentName:"tr"},{align:null}),"filterFields ",mdx("em",{parentName:"td"},"(required)")),mdx("td",t({parentName:"tr"},{align:null}),"\u7B5B\u9009\u5B57\u6BB5"),mdx("td",t({parentName:"tr"},{align:null}),"FilterFieldProps","[","]"),mdx("td",t({parentName:"tr"},{align:null}),"-"),mdx("td",t({parentName:"tr"},{align:null}),"-")),mdx("tr",{parentName:"tbody"},mdx("td",t({parentName:"tr"},{align:null}),"formData ",mdx("em",{parentName:"td"},"(required)")),mdx("td",t({parentName:"tr"},{align:null}),"\u8868\u5355\u6570\u636E"),mdx("td",t({parentName:"tr"},{align:null}),"Record<string, unknown",">"),mdx("td",t({parentName:"tr"},{align:null}),"-"),mdx("td",t({parentName:"tr"},{align:null}),"-")),mdx("tr",{parentName:"tbody"},mdx("td",t({parentName:"tr"},{align:null}),"onPinChange"),mdx("td",t({parentName:"tr"},{align:null}),"\u56FA\u5B9A\u5B57\u6BB5\u53D8\u5316\u56DE\u8C03"),mdx("td",t({parentName:"tr"},{align:null}),"((field: string, visible: boolean) => void)"),mdx("td",t({paren